const data = $input.first().json;

let memory = {};
try {
  const stored = $getWorkflowStaticData('global');
  memory = stored.videoMemory || {};
} catch(e) { memory = {}; }

if (!memory.totalVideos) memory.totalVideos = 0;
if (!memory.lastTopics) memory.lastTopics = [];
if (!memory.nichePerformance) memory.nichePerformance = {};
if (!memory.preferredStyle) memory.preferredStyle = 'cinematic documentary';
if (!memory.bestPerformingNiche) memory.bestPerformingNiche = 'general';
if (!memory.channelName) memory.channelName = 'Empires Untold';
if (!memory.defaultVoice) memory.defaultVoice = 'Max';
if (!memory.voicePerformance) memory.voicePerformance = {};
if (!memory.bestVoicePerNiche) memory.bestVoicePerNiche = {};
if (!memory.totalCost) memory.totalCost = 0;
if (!memory.seriesData) memory.seriesData = {};
if (!memory.qualityScores) memory.qualityScores = [];

memory.totalVideos += 1;

const topic = data.customTopic || 'auto';
memory.lastTopics.unshift(topic);
if (memory.lastTopics.length > 20) memory.lastTopics = memory.lastTopics.slice(0,20);

const niche = data.niche || 'general';
if (!memory.nichePerformance[niche]) memory.nichePerformance[niche] = { count: 0, avgViews: 0 };
memory.nichePerformance[niche].count += 1;

let bestNiche = 'general', bestCount = 0;
for (const [n, s] of Object.entries(memory.nichePerformance)) {
  if (s.count > bestCount) { bestNiche = n; bestCount = s.count; }
}
memory.bestPerformingNiche = bestNiche;

if (data.seriesName) {
  if (!memory.seriesData[data.seriesName]) memory.seriesData[data.seriesName] = { episodes: 0, lastEp: 0 };
  memory.seriesData[data.seriesName].episodes += 1;
  memory.seriesData[data.seriesName].lastEp = parseInt(data.seriesEp || 1);
}

try {
  const stored = $getWorkflowStaticData('global');
  stored.videoMemory = memory;
} catch(e) {}

return [{ json: {
  ...data,
  memory: {
    totalVideos: memory.totalVideos,
    recentTopics: memory.lastTopics.slice(0,5),
    bestNiche: memory.bestPerformingNiche,
    preferredStyle: memory.preferredStyle,
    channelName: memory.channelName,
    avoidRepeat: memory.lastTopics.slice(0,3),
    defaultVoice: memory.defaultVoice,
    bestVoicePerNiche: memory.bestVoicePerNiche,
    totalCost: memory.totalCost,
    seriesData: memory.seriesData,
    qualityScores: memory.qualityScores.slice(0,10)
  }
}}];

const stored = $getWorkflowStaticData('global');
const memory = stored.videoMemory || {};
const today = new Date().toISOString().split('T')[0];
const todayCount = (stored.dailyCount || {})[today] || 0;
const monthlyCost = stored.monthlyCost || 0;
const paused = stored.paused || false;
const alertLog = stored.securityLog || [];
const lastAlert = alertLog.find(e => e.alert) || null;

const statusMsg = `AI Video Bot v6 - System Status\n\n` +
  `Status: ${paused ? 'PAUSED ?' : 'RUNNING'}\n` +
  `Videos Today: ${todayCount}/10\n` +
  `Total Videos All Time: ${memory.totalVideos || 0}\n` +
  `Monthly Spend: $${monthlyCost.toFixed(2)} / $80 budget\n` +
  `Auto-Pause Limit: $100\n\n` +
  `Best Niche: ${memory.bestPerformingNiche || 'general'}\n` +
  `Default Voice: ${memory.defaultVoice || 'Max'}\n` +
  `Channel: ${memory.channelName || 'Empires Untold'}\n\n` +
  `Last Security Alert: ${lastAlert ? lastAlert.ts + ' - ' + lastAlert.reason : 'None'}\n\n` +
  `APIs Ready: Anthropic, ElevenLabs, fal.ai, OpenAI, Creatomate, Pexels, Google AI Studio\n` +
  `Send STATUS anytime to refresh.`;

return [{ json: { ...($input.first().json), statusMsg } }];

const stored = $getWorkflowStaticData('global');
stored.paused = true;
stored.pausedAt = new Date().toISOString();
return [{ json: { ...($input.first().json), paused: true, msg: 'Workflow PAUSED. All scheduled runs halted. Daily 9AM auto-run stopped. Send RESUME to restart.' } }];

const stored = $getWorkflowStaticData('global');
stored.paused = false;
stored.resumedAt = new Date().toISOString();
return [{ json: { ...($input.first().json), paused: false, msg: 'Workflow RESUMED! All systems operational. Daily auto-runs will continue normally.' } }];

const stored = $getWorkflowStaticData('global');
const monthlyCost = stored.monthlyCost || 0;
const costLog = stored.costLog || [];
const thisMonth = new Date().toISOString().slice(0,7);

const monthlyEntries = costLog.filter(e => e.date && e.date.startsWith(thisMonth));
const byApi = { anthropic: 0, elevenlabs: 0, openai: 0, fal: 0, creatomate: 0 };
monthlyEntries.forEach(e => {
  byApi.anthropic += e.anthropic || 0;
  byApi.elevenlabs += e.elevenlabs || 0;
  byApi.openai += e.openai || 0;
  byApi.fal += e.fal || 0;
  byApi.creatomate += e.creatomate || 0;
});

const avgCost = monthlyEntries.length > 0 ? (monthlyCost / monthlyEntries.length).toFixed(2) : '0.00';
const budgetPct = ((monthlyCost / 80) * 100).toFixed(0);

const costReport = `Monthly Cost Report - ${thisMonth}\n\n` +
  `Total Spent: $${monthlyCost.toFixed(2)} (${budgetPct}% of $80 budget)\n` +
  `Avg Per Video: $${avgCost}\n` +
  `Videos This Month: ${monthlyEntries.length}\n\n` +
  `Breakdown:\n` +
  `Claude (Anthropic): $${byApi.anthropic.toFixed(2)}\n` +
  `ElevenLabs: $${byApi.elevenlabs.toFixed(2)}\n` +
  `DALL-E (OpenAI): $${byApi.openai.toFixed(2)}\n` +
  `Kling (fal.ai): $${byApi.fal.toFixed(2)}\n` +
  `Creatomate: $${byApi.creatomate.toFixed(2)}\n\n` +
  `Budget Alert: $80 | Auto-Pause: $100`;

return [{ json: { ...($input.first().json), costReport } }];

const stored = $getWorkflowStaticData('global');
const log = (stored.securityLog || []).slice(0,20);
let msg = 'Security Log - Last 20 Events:\n\n';
if (log.length === 0) {
  msg += 'No events recorded yet.';
} else {
  log.forEach((e, i) => {
    const time = e.ts ? e.ts.slice(5,19).replace('T',' ') : '?';
    const status = e.blocked ? `BLOCKED [${e.reason || 'unknown'}]` : 'OK';
    msg += `${i+1}. [${time}] ${e.action || e.cmd || 'cmd'} from ${e.chatId || '?'} (${e.src || '?'}) - ${status}\n`;
  });
}
return [{ json: { ...($input.first().json), securityLogMsg: msg } }];

const stored = $getWorkflowStaticData('global');
const memory = stored.videoMemory || {};
const voicePerf = memory.voicePerformance || {};
const bestPerNiche = memory.bestVoicePerNiche || {};
const videoCount = memory.totalVideos || 0;

let msg = 'Voice Performance Report\n\n';

if (Object.keys(voicePerf).length === 0) {
  msg += 'No voice data yet. Create some videos to build analytics!\n\n';
  msg += 'Available voices:\n1. Taksh - Hindi, warm cultural\n2. Bradford - Serious, political, dark\n3. Max - Documentary, educational (default)\n4. Samantha - Emotional, true crime, intimate';
} else {
  msg += 'Voice Usage Stats:\n';
  const voices = ['Taksh','Bradford','Max','Samantha'];
  voices.forEach(v => {
    const d = voicePerf[v] || { count: 0, avgScore: 0 };
    const pct = videoCount > 0 ? ((d.count / videoCount) * 100).toFixed(0) : 0;
    msg += `${v}: ${d.count} videos (${pct}%), avg quality ${(d.avgScore || 0).toFixed(1)}/10\n`;
  });
  msg += '\nBest Voice Per Niche:\n';
  if (Object.keys(bestPerNiche).length === 0) {
    msg += 'Not enough data yet.';
  } else {
    for (const [niche, voice] of Object.entries(bestPerNiche)) {
      msg += `${niche}: ${voice}\n`;
    }
  }
  msg += `\nDefault: ${memory.defaultVoice || 'Max (auto-select)'}`;
}

return [{ json: { ...($input.first().json), voiceReportMsg: msg } }];

const data = $input.first().json;
const pick = data.thumbnailPick || 1;
const stored = $getWorkflowStaticData('global');
const pendingVideo = stored.pendingVideo || {};

let selectedUrl = '';
if (pick === 1) selectedUrl = pendingVideo.thumbAUrl || pendingVideo.thumbUrl || '';
else if (pick === 2) selectedUrl = pendingVideo.thumbBUrl || '';
else if (pick === 3) selectedUrl = pendingVideo.thumbCUrl || '';

if (selectedUrl) {
