const stored = $getWorkflowStaticData("global");
const d = stored.pendingVideoData || {};
const FAL_KEY = "FAL_AI_KEY_HERE";
const scriptSegments = d.script_segments || [];
const existingUrls = d.videoUrls || [];

if (scriptSegments.length > 0) {
  const videoUrls = [];
  for (let i = 0; i < Math.min(3, scriptSegments.length); i++) {
    const seg = scriptSegments[i];
    const prompt = seg.visual_prompt || (d.topic + " cinematic dramatic historical scene South Asian, moody lighting, high contrast");
    let added = false;

    // Primary: fal-ai/veo3
    try {
      const res = await fetch("https://fal.run/fal-ai/veo3", {
        method: "POST",
        headers: { "Authorization": "Key " + FAL_KEY, "Content-Type": "application/json" },
        body: JSON.stringify({ prompt: prompt, duration: 5, aspect_ratio: "9:16" })
      });
      const data = await res.json();
      if (data.video?.url) { videoUrls.push(data.video.url); added = true; }
      else if (data.url) { videoUrls.push(data.url); added = true; }
    } catch(e) {}

    if (!added) {
      // Fallback: fal-ai/seedance-v1-5-lite
      try {
        const res2 = await fetch("https://fal.run/fal-ai/seedance-v1-5-lite", {
          method: "POST",
          headers: { "Authorization": "Key " + FAL_KEY, "Content-Type": "application/json" },
          body: JSON.stringify({ prompt: prompt, duration: 5 })
        });
        const data2 = await res2.json();
        if (data2.video?.url) { videoUrls.push(data2.video.url); added = true; }
        else if (data2.url) { videoUrls.push(data2.url); added = true; }
      } catch(e2) {}
    }

    // Final fallback: use existing Pexels URLs
    if (!added && existingUrls[i]) videoUrls.push(existingUrls[i]);
  }

  const allUrls = [...videoUrls, ...existingUrls].filter((u,i,a) => u && a.indexOf(u)===i);
  stored.pendingVideoData = { ...d, aiVideoUrls: videoUrls, videoUrls: allUrls };
  return [{ json: { ...d, aiVideoUrls: videoUrls, videoUrls: allUrls } }];
}

// No segments: pass through existing video URLs
return [{ json: { ...d, aiVideoUrls: [], videoUrls: existingUrls } }];

