const item = $input.first().json;
const chatId = String(item.chatId || '');
const ALLOWED_ID = '8370599696';
const src = item.src || '';

const stored = $getWorkflowStaticData('global');
if (!stored.securityLog) stored.securityLog = [];
if (!stored.dailyCount) stored.dailyCount = {};
if (stored.paused === undefined) stored.paused = false;
if (!stored.monthlyCost) stored.monthlyCost = 0;
if (!stored.costLog) stored.costLog = [];

const logEntry = { ts: new Date().toISOString(), chatId, src, action: item.action, cmd: item.cmd };

if (stored.paused && item.action !== 'RESUME' && item.action !== 'STATUS') {
  logEntry.blocked = true; logEntry.reason = 'workflow_paused';
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'workflow_paused' } }];
}

if (stored.monthlyCost > 100 && item.action === 'CREATE') {
  logEntry.blocked = true; logEntry.reason = 'monthly_budget_exceeded';
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'monthly_budget_exceeded', sendAlert: true } }];
}

if ((src === 'telegram' || src === 'telegram_callback') && chatId !== ALLOWED_ID) {
  logEntry.blocked = true; logEntry.reason = 'unauthorized_user'; logEntry.alert = true;
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'unauthorized_user', sendAlert: true } }];
}

const today = new Date().toISOString().split('T')[0];
if (!stored.dailyCount[today]) stored.dailyCount[today] = 0;

if (item.action === 'CREATE' && stored.dailyCount[today] >= 10) {
  logEntry.blocked = true; logEntry.reason = 'rate_limit';
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'rate_limit_10_per_day' } }];
}

if (item.action === 'CREATE') stored.dailyCount[today]++;

logEntry.blocked = false;
stored.securityLog.unshift(logEntry);
if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);

return [{ json: { ...item, blocked: false, todayCount: stored.dailyCount[today] || 0 } }];

