  return [{ json: { error: true, errorMsg: 'Render failed: ' + errMsg, renderId, renderDone: false, title: scriptMeta.title || '', hook: scriptMeta.hook || '' } }];
}

const retryCount = (stored.renderRetryCount || 0) + 1;
stored.renderRetryCount = retryCount;

if (retryCount >= 5) {
  stored.renderRetryCount = 0;
  return [{ json: { error: true, errorMsg: 'Render timed out after 5 retries. Last status: ' + status, renderId, renderDone: false, title: scriptMeta.title || '', hook: scriptMeta.hook || '' } }];
}

return [{ json: { ...(item || {}), renderDone: false, retryCount, renderId, renderStatus: status, title: scriptMeta.title || '', hook: scriptMeta.hook || '' } }];

const stored = $getWorkflowStaticData('global');
const d = stored.pendingVideoData || {};
const FAL_KEY = ''; // Set fal.ai key to enable AI video — Veo 3.1 ~$0.50/clip
const scriptSegments = d.script_segments || [];
const existingUrls = d.videoUrls || [];

if (FAL_KEY && scriptSegments.length > 0) {
  const videoUrls = [];
  for (let i = 0; i < Math.min(4, scriptSegments.length); i++) {
    const prompt = scriptSegments[i].visual_prompt || (d.topic + ' cinematic dramatic scene South Asian history');
    let added = false;
    try {
      const res = await fetch('https://fal.run/fal-ai/veo3', {
        method: 'POST',
        headers: { 'Authorization': 'Key ' + FAL_KEY, 'Content-Type': 'application/json' },
        body: JSON.stringify({ prompt, duration: 5, aspect_ratio: '9:16' })
      });
      const data = await res.json();
      if (data.video?.url) { videoUrls.push(data.video.url); added = true; }
    } catch(e) {}
    if (!added) {
      try {
        const res = await fetch('https://fal.run/fal-ai/seedance-v1-5-lite', {
          method: 'POST',
          headers: { 'Authorization': 'Key ' + FAL_KEY, 'Content-Type': 'application/json' },
          body: JSON.stringify({ prompt, duration: 5, aspect_ratio: '9:16' })
        });
        const data = await res.json();
        if (data.video?.url) { videoUrls.push(data.video.url); added = true; }
      } catch(e) {}
    }
    if (!added && existingUrls[i]) videoUrls.push(existingUrls[i]);
  }
  const videoSource = videoUrls.some(u => u.includes('fal')) ? 'fal_ai' : 'pexels_free';
  const updatedD = { ...d, videoUrls, videoSource };
  stored.pendingVideoData = updatedD;
  return [{ json: { ...$input.first().json, ...updatedD } }];
}

